function addCladdingBoards(
  mesh: THREE.Mesh,
  wallLenM: number,
  wallHeightM: number,
  boardWidthMm = 120,
  gapMm = 10,
): void {
  const pitchM  = (boardWidthMm + gapMm) / 1000;
  const count   = Math.max(1, Math.floor(wallLenM / pitchM));
  const boardW  = 0.012;    // 12 mm proud of wall face
  const boardH  = wallHeightM - 0.05;
  const boardD  = pitchM - 0.002;   // slight gap between boards

  // Read wall face color for boards (same token as wall body)
  const boardColor = readToken('--cat-wall', '#9ca3af');
  const boardMat = new THREE.MeshStandardMaterial({
    color: boardColor,
    roughness: 0.85,
    metalness: 0,
  });

  const boardGeom = new THREE.BoxGeometry(boardW, boardH, boardD);

  for (let i = 0; i < count; i++) {
    const board = new THREE.Mesh(boardGeom, boardMat);
    // In wall-local space: X is the face-normal direction (outward = +X),
    // Y is up, Z is along the wall length.
    // Place boards at the wall face (X = +wallThick/2 + boardW/2) and
    // spread along Z from -wallLen/2 to +wallLen/2.
    const zPos = -wallLenM / 2 + (i + 0.5) * pitchM;
    board.position.set(0, 0, zPos);   // X offset added below
    board.castShadow = board.receiveShadow = true;
    mesh.add(board);
  }

  // Nudge boards to sit on the wall face. We don't know thick here,
  // but we can compute it from the mesh geometry bounding box.
  const box = new THREE.Box3().setFromObject(mesh);
  const wallHalfThick = (box.max.x - box.min.x) / 2;   // after rotation it's Z not X
